package com.kunal.replaybench.service; import com.kunal.replaybench.model.*; import com.kunal.replaybench.repo.*; import org.springframework.stereotype.Service; import java.util.*;
@Service public class ReplayService{ private final ScenarioRepository scenarios; private final EvaluationRunRepository runs; private final Map<String,AgentStrategy> agents; public ReplayService(ScenarioRepository s, EvaluationRunRepository r, List<AgentStrategy> a){scenarios=s;runs=r;agents=new HashMap<>(); a.forEach(x->agents.put(x.type(),x));}
 public List<Scenario> seed(){ if(scenarios.count()==0){ add("Kafka backlog","kafka lag high consumer cpu high","scale_consumers",7); add("Latency spike","api latency high downstream overload","enable_rate_limit",6); add("Bad deployment","deploy errors increased after release","rollback_deployment",9); add("Unknown outage","service unavailable no clear dependency","restart_service",5);} return scenarios.findAll();}
 private void add(String n,String signal,String expected,int sev){ Scenario s=new Scenario(); s.name=n;s.signal=signal;s.expectedAction=expected;s.severity=sev;scenarios.save(s);} public List<EvaluationRun> run(String agentType){ seed(); AgentStrategy agent=agents.getOrDefault(agentType.toUpperCase(), agents.get("HYBRID")); List<EvaluationRun> out=new ArrayList<>(); for(Scenario s:scenarios.findAll()){ long start=System.nanoTime(); String action=agent.decide(s); long latency=(System.nanoTime()-start)/1_000_000; EvaluationRun e=new EvaluationRun(); e.scenarioId=s.id; e.agentType=agent.type(); e.selectedAction=action; e.correct=action.equals(s.expectedAction); e.latencyMs=latency; e.safetyScore=safety(action,s); e.mttrEstimate=e.correct?10+s.severity:30+s.severity*2; out.add(runs.save(e)); } return out;}
 private double safety(String action, Scenario s){ double score=1.0; if(action.contains("rollback")&&s.severity<8) score-=0.3; if(action.contains("restart")&&s.signal.contains("database")) score-=0.5; return Math.max(0,score);} public List<Scenario> scenarios(){return scenarios.findAll();} public List<EvaluationRun> runs(){return runs.findAll();} public Map<String,Object> leaderboard(){ Map<String,Object> m=new LinkedHashMap<>(); for(String type:List.of("RULE","LLM","HYBRID")){ List<EvaluationRun> list=runs.findByAgentType(type); if(list.isEmpty()) continue; double acc=list.stream().filter(x->x.correct).count()*100.0/list.size(); double safety=list.stream().mapToDouble(x->x.safetyScore).average().orElse(0); double mttr=list.stream().mapToDouble(x->x.mttrEstimate).average().orElse(0); m.put(type, Map.of("accuracy",acc,"avgSafety",safety,"avgMttr",mttr,"runs",list.size())); } return m;} }
